"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[23],{1052(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"link","href":"/taco/docs/intro","label":"Introduction","docId":"intro","unlisted":false},{"type":"link","href":"/taco/docs/task-types","label":"Task Types","docId":"task-types","unlisted":false},{"type":"link","href":"/taco/docs/agent-card-extensions","label":"Agent Card Extensions","docId":"agent-card-extensions","unlisted":false},{"type":"category","label":"Data Schemas","items":[{"type":"link","href":"/taco/docs/schemas/bom-v1","label":"bom-v1 \u2014 Bill of Materials","docId":"schemas/bom-v1","unlisted":false},{"type":"link","href":"/taco/docs/schemas/rfi-v1","label":"rfi-v1 \u2014 Request for Information","docId":"schemas/rfi-v1","unlisted":false},{"type":"link","href":"/taco/docs/schemas/estimate-v1","label":"estimate-v1 \u2014 Cost Estimate","docId":"schemas/estimate-v1","unlisted":false},{"type":"link","href":"/taco/docs/schemas/schedule-v1","label":"schedule-v1 \u2014 Project Schedule","docId":"schemas/schedule-v1","unlisted":false},{"type":"link","href":"/taco/docs/schemas/quote-v1","label":"quote-v1 \u2014 Supplier Quote","docId":"schemas/quote-v1","unlisted":false},{"type":"link","href":"/taco/docs/schemas/change-order-v1","label":"change-order-v1 \u2014 Change Order","docId":"schemas/change-order-v1","unlisted":false}],"collapsed":true,"collapsible":true,"href":"/taco/docs/schemas/"},{"type":"link","href":"/taco/docs/sdk","label":"SDK Reference","docId":"sdk","unlisted":false},{"type":"link","href":"/taco/docs/security","label":"Security","docId":"security","unlisted":false}]},"docs":{"agent-card-extensions":{"id":"agent-card-extensions","title":"Agent Card Extensions","description":"TACO extends the standard A2A Agent Card with construction-specific metadata using the x-construction extension field. These fields are optional \u2014 any A2A client that does not understand them will simply ignore them per the A2A specification.","sidebar":"docsSidebar"},"intro":{"id":"intro","title":"Introduction","description":"Every construction tool should be agent-compatible. TACO gives them a shared language.","sidebar":"docsSidebar"},"schemas/bom-v1":{"id":"schemas/bom-v1","title":"bom-v1 \u2014 Bill of Materials","description":"The Bill of Materials schema defines a standardized format for construction material takeoffs. It captures line items with quantities, materials, sizes, and provenance metadata.","sidebar":"docsSidebar"},"schemas/change-order-v1":{"id":"schemas/change-order-v1","title":"change-order-v1 \u2014 Change Order","description":"The Change Order schema will define a standardized format for construction change order analysis, including cost impact, schedule impact, and scope modifications.","sidebar":"docsSidebar"},"schemas/estimate-v1":{"id":"schemas/estimate-v1","title":"estimate-v1 \u2014 Cost Estimate","description":"The Estimate schema defines a standardized format for construction cost estimates. It captures line-item costs (material, labor, equipment), summary totals, and overhead/profit calculations.","sidebar":"docsSidebar"},"schemas/index":{"id":"schemas/index","title":"Data Schemas","description":"TACO defines typed JSON schemas for construction artifacts. These schemas ensure that the output from one agent is valid input for the next \u2014 enabling multi-agent workflows without custom integration code.","sidebar":"docsSidebar"},"schemas/quote-v1":{"id":"schemas/quote-v1","title":"quote-v1 \u2014 Supplier Quote","description":"The Quote schema defines a standardized format for supplier material quotes. It captures pricing, availability, lead times, and terms.","sidebar":"docsSidebar"},"schemas/rfi-v1":{"id":"schemas/rfi-v1","title":"rfi-v1 \u2014 Request for Information","description":"The RFI schema defines a standardized format for construction Requests for Information. It captures design conflicts, missing information, and clarification requests with drawing references and priority levels.","sidebar":"docsSidebar"},"schemas/schedule-v1":{"id":"schemas/schedule-v1","title":"schedule-v1 \u2014 Project Schedule","description":"The Schedule schema will define a standardized format for construction project schedules, including activities, dependencies, milestones, and resource assignments.","sidebar":"docsSidebar"},"sdk":{"id":"sdk","title":"SDK Reference","description":"The TACO Python SDK provides models, a server framework, a client, and an agent registry for building A2A-compatible construction agents.","sidebar":"docsSidebar"},"security":{"id":"security","title":"Security","description":"Security in TACO builds on A2A\'s native authentication model and adds construction-specific authorization concepts: project-scoped credentials, trade-level permission boundaries, and a registry trust model for verified agents.","sidebar":"docsSidebar"},"task-types":{"id":"task-types","title":"Task Types","description":"Task types are the verbs of the TACO ecosystem. Each task type defines a category of work that an agent can advertise and execute. Agents declare their supported task types in the x-construction.taskType field of their Agent Card skills.","sidebar":"docsSidebar"}}}}')}}]);